SELECT MAX(JOURNAL.jdRecNo) as indexed_id, QUOTEH.REF AS quote_id, QUOTEH.UF_SHIPMENTREF AS shipment_id, QUOTEH.UF_SHIPMENTNAME AS shipment_name, QUOTEH.OHQTEXPIRYDATE AS expiry_date, QUOTEH.OHSPLPRICEPOINT AS price_date, QUOTEH.TITLE AS quote_reference, QUOTEH.UF_CSA AS csa_code, QUOTEH.OHSPLTERMS AS quote_type_int, QUOTEH.UF_VERSION AS version, QUOTEH.UF_SHIPOUT AS shipment_date, QUOTEH.NOTES AS special_instructions, QUOTSTAT.OSSTATE AS quote_status, QUOTEH.CUSTCODE AS customer_code FROM QUOTEH LEFT JOIN QUOTSTAT ON QUOTEH.REF = QUOTSTAT.REF AND QUOTSTAT.LINENO = 18 JOIN JOURNAL ON JOURNAL.jdRef = QUOTEH.REF WHERE JOURNAL.jdRecNo > ? AND JOURNAL.jdRecNo < ? AND QUOTEH.INSTATUS = 1 AND QUOTEH.QTRESULTORDERREF IS NULL GROUP BY quote_id;

