SELECT ORDERH.REF AS order_id, ORDERH.QTRESULTORDERREF AS original_quote_id, ORDERH.UF_SHIPMENTREF AS shipment_id, ORDERH.UF_SHIPMENTNAME AS shipment_name, ORDERH.OHQTEXPIRYDATE AS expiry_date, ORDERH.OHSPLPRICEPOINT AS price_date, ORDERH.OHSPLTERMS AS quote_type_int, ORDERH.UF_VERSION AS version, ORDERH.UF_CSA AS csa_code, ORDERH.OHINVDATE AS invoice_date, ORDERH.OHINVREF AS invoice_id, ORDERH.UF_SHIPOUT AS shipment_date, ORDERH.NOTES AS special_instructions, ORDERH.TITLE AS order_reference, ORDERH.CRNOTE AS credit_note, ORDERH.CUSTCODE AS customer_code FROM ORDERH WHERE ORDERH.QTRESULTORDERREF IS NOT NULL WHERE ORDERH.INSTATUS = 1 AND (CAST(ORDERH.REF AS INTEGER) BETWEEN ? AND ?);

-- line 134
SELECT QUOTEI.REF AS id, QUOTEI.QUANTITY as quantity, QUOTEI.LINE as line_num, QUOTEI.PRICE, QUOTEI.EXTRATYPE as extra_type, QUOTEI.UF_LOCKPRICE AS fixed_price, LEFT(PRODUCT.CODE, 1) + 'UK' AS BRAND_CODE, LEFT(PRODUCT.GROUP, 2) + 'UK' AS MAIN_GROUP_CODE, LEFT(PRODUCT.GROUP, 4) + 'UK' AS SUB_GROUP_CODE, LEFT(PRODUCT.GROUP, 6) + 'UK' AS SUB_SUB_GROUP_CODE, QUOTEI.DESC1 as doc_prod_desc1, NIINGRED.NIBRAND, NIINGRED.NILDESC, PRODUCT.CODE, PRODUCT.CUNIT, PRODUCT.UF_IBARCODE, PRODUCT.UF_O_BARCODE, PRODUCT.UF_PRE_PRICED, PRODUCT.MASSNET, PRODUCT.MASSGROSS, PRODUCT.VOL, PRODUCT.COMMOD, PRODUCT.UF_CSSPALLET, PRODUCT.UF_CSSLAYER, PRODUCT.UF_BBEROTDATE, PRODUCT.UF_WH_SHELF, PRODUCT.PRUSER01, PRODUCT.PRUSER02, PRODUCT.PRUSER03 FROM QUOTEI JOIN PRODUCT ON QUOTEI.PRODUCT = PRODUCT.CODE LEFT JOIN NIINGRED ON PRODUCT.UF_IBARCODE = NIINGRED.NIEAN AND NIINGRED.NILDESC IS NOT NULL AND NIINGRED.NILANG = 'ENGLISH' WHERE QUOTEI.REF = ?;

